import json
import random


def get_rand_list(file_path, edit_num, seed):
    # Open and load the JSON file
    with open(file_path, 'r') as f:
        dataset = json.load(f)

    # you can use seed = 100
    random.seed(seed)
    caseids = [d['case_id'] for d in dataset]
    retval = random.sample(caseids, edit_num)
    return retval


